class Playground {
    async run(inputs) {
        // Parse Input
        const inputStr = inputs[0] || "1,8,6,2,5,4,8,3,7";
        const heights = inputStr.split(',').map(num => parseInt(num.trim()));

        // Initialize Visualizer Slots
        await this.heights.init(heights);
        await this.vars.init([]);

        let left = 0;
        let right = heights.length - 1;
        let maxArea = 0;

        this.vars.put("maxArea", 0);
        this.vars.put("left", left);
        this.vars.put("right", right);

        while (left < right) {
            // Update State Visualization
            this.vars.put("left", left);
            this.vars.put("right", right);

            const hLeft = heights[left];
            const hRight = heights[right];
            const width = right - left;
            const minHeight = Math.min(hLeft, hRight);
            const currentArea = minHeight * width;

            this.vars.put("currentArea", currentArea);
            this.vars.put("width", width);
            this.vars.put("minHeight", minHeight);

            // Highlight the two bars forming the container
            this.heights.highlight(left, "#00e0ff");
            this.heights.highlight(right, "#00e0ff");

            if (currentArea > maxArea) {
                maxArea = currentArea;
                this.vars.put("maxArea", maxArea);
                this.log(`New max area found: ${maxArea} (Min Height: ${minHeight} * Width: ${width})`);
            } else {
                this.log(`Current area: ${currentArea}. Max area remains: ${maxArea}`);
            }

            await this.await();

            // Clear highlights before moving pointers
            this.heights.highlight(left, null);
            this.heights.highlight(right, null);

            // Logic: Move the smaller pointer to potentially find a taller bar 
            // that offsets the loss in width.
            if (hLeft < hRight) {
                this.log(`Left height (${hLeft}) < Right height (${hRight}). Incrementing Left pointer.`);
                left++;
            } else {
                this.log(`Right height (${hRight}) <= Left height (${hLeft}). Decrementing Right pointer.`);
                right--;
            }

            await this.await();
        }

        this.log(`Algorithm finished. Maximum water volume: ${maxArea}`);
        return maxArea;
    }
}
